}

enum class TransactionStatus {
    PENDING,
    PROCESSING,
    COMPLETED,
    FAILED,
    CANCELLED,
    REFUNDED
}

sealed class PaymentResult {
    data class Success(val transaction: Transaction) : PaymentResult()
