// ==================== Security Module ====================

class SecurityManager(private val context: Context) {

    companion object {
        private const val KEYSTORE_ALIAS = "PaymentKeyAlias"
        private const val ANDROID_KEYSTORE = "AndroidKeyStore"
        private const val TRANSFORMATION = "AES/GCM/NoPadding"
        private const val GCM_TAG_LENGTH = 128
        private const val ENCRYPTED_PREFS_FILE = "encrypted_payment_prefs"
        private const val TAG = "SecurityManager"
    }

    private val keyStore: KeyStore = KeyStore.getInstance(ANDROID_KEYSTORE).apply { load(null) }

    private val masterKey: MasterKey by lazy {
        MasterKey.Builder(context)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .build()
    }

    val encryptedPrefs by lazy {
        EncryptedSharedPreferences.create(
            context,
            ENCRYPTED_PREFS_FILE,
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    init {
        generateKeyIfNeeded()
    }

    private fun generateKeyIfNeeded() {
        try {
            if (!keyStore.containsAlias(KEYSTORE_ALIAS)) {
                val keyGenerator = KeyGenerator.getInstance(
                    KeyProperties.KEY_ALGORITHM_AES,
                    ANDROID_KEYSTORE
                )
                val builder = KeyGenParameterSpec.Builder(
                    KEYSTORE_ALIAS,
                    KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
                )
                    .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                    .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                    .setKeySize(256)
                    .setRandomizedEncryptionRequired(true)

                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                    builder.setInvalidatedByBiometricEnrollment(false)
                }

                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
                    builder.setUnlockedDeviceRequired(false)
                    builder.setIsStrongBoxBacked(isStrongBoxAvailable())
                }

                keyGenerator.init(builder.build())
                keyGenerator.generateKey()
            }
        } catch (e: Exception) {
            Log.e(TAG, "Key generation failed", e)
        }
    }

    private fun isStrongBoxAvailable(): Boolean {
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
            context.packageManager.hasSystemFeature("android.hardware.strongbox_keystore")
        } else {
            false
        }
    }

    private fun getSecretKey(): SecretKey {
        val entry = keyStore.getEntry(KEYSTORE_ALIAS, null) as KeyStore.SecretKeyEntry
        return entry.secretKey
    }

    fun encrypt(plainText: String): String {
        return try {
            val cipher = Cipher.getInstance(TRANSFORMATION)
            cipher.init(Cipher.ENCRYPT_MODE, getSecretKey())
            val iv = cipher.iv
            val encryptedBytes = cipher.doFinal(plainText.toByteArray(Charsets.UTF_8))
            val combined = iv + encryptedBytes
            Base64.encodeToString(combined, Base64.NO_WRAP)
        } catch (e: Exception) {
            Log.e(TAG, "Encryption failed", e)
            throw SecurityException("Failed to encrypt data", e)
        }
    }

    fun decrypt(encryptedText: String): String {
        return try {
            val decoded = Base64.decode(encryptedText, Base64.NO_WRAP)
            val iv = decoded.copyOfRange(0, 12)
            val encryptedBytes = decoded.copyOfRange(12, decoded.size)
            val cipher = Cipher.getInstance(TRANSFORMATION)
            val spec = GCMParameterSpec(GCM_TAG_LENGTH, iv)
            cipher.init(Cipher.DECRYPT_MODE, getSecretKey(), spec)
            String(cipher.doFinal(encryptedBytes), Charsets.UTF_8)
        } catch (e: Exception) {
            Log.e(TAG, "Decryption failed", e)
            throw SecurityException("Failed to decrypt data", e)
        }
    }

    fun hashData(data: String): String {
        val salt = generateSalt()
        val digest = MessageDigest.getInstance("SHA-256")
        digest.update(salt)
        val hash = digest.digest(data.toByteArray(Charsets.UTF_8))
        val combined = salt + hash
        return Base64.encodeToString(combined, Base64.NO_WRAP)
    }

    private fun generateSalt(): ByteArray {
        val salt = ByteArray(16)
        SecureRandom().nextBytes(salt)
        return salt
    }

    fun generateTransactionToken(): String {
        val random = SecureRandom()
        val bytes = ByteArray(32)
        random.nextBytes(bytes)
        return Base64.encodeToString(bytes, Base64.NO_WRAP or Base64.URL_SAFE)
    }

    fun securelyStoreValue(key: String, value: String) {
        encryptedPrefs.edit().putString(key, value).apply()
    }

    fun securelyRetrieveValue(key: String): String? {
        return encryptedPrefs.getString(key, null)
    }

    fun clearSecureStorage() {
        encryptedPrefs.edit().clear().apply()
    }
}

// ==================== Data Sanitization ====================

object DataSanitizer {

    fun sanitizeAmount(amount: String): BigDecimal? {
        return try {
            val sanitized = amount.replace(Regex("[^0-9.]"), "")
            val decimal = BigDecimal(sanitized).setScale(2, RoundingMode.HALF_UP)
            if (decimal <= BigDecimal.ZERO) null else decimal
        } catch (e: Exception) {
            null
        }
    }

    fun sanitizeString(input: String): String {
        return input.replace(Regex("[<>\"'&;(){}\\[\\]]"), "")
            .trim()
            .take(500)
    }

    fun maskCardNumber(cardNumber: String): String {
        val cleaned = cardNumber.replace(Regex("[^0-9]"), "")
        if (cleaned.length < 4) return "****"
        return "**** **** **** ${cleaned.takeLast(4)}"
    }

    fun maskEmail(email: String): String {
        val parts = email.split("@")
        if (parts.size != 2) return "***@***"
        val name = parts[0]
        val domain = parts[1]
        val maskedName = if (name.length > 2) {
            "${name.first()}${"*".repeat(name.length - 2)}${name.last()}"
        } else {
            "*".repeat(name.length)
        }
        return "$maskedName@$domain"
    }

    fun validateAmount(amount: BigDecimal, minAmount: BigDecimal = BigDecimal("0.01"), maxAmount: BigDecimal = BigDecimal("99999.99")): Boolean {
        return amount in minAmount..maxAmount
    }
}

// ==================== Transaction Logger ====================

class TransactionLogger(private val securityManager: SecurityManager) {

    companion object {
        private const val TRANSACTION_LOG_KEY = "transaction_log"
        private const val MAX_LOG_ENTRIES = 1000
    }

    private val transactionCache = ConcurrentHashMap<String, Transaction>()

    fun logTransaction(transaction: Transaction) {
        transactionCache[transaction.id] = transaction
        persistTransaction(transaction)
    }

    private fun persistTransaction(transaction: Transaction) {
        try {
            val serialized = serializeTransaction(transaction)
            val encrypted = securityManager.encrypt(serialized)
            val existing = securityManager.securelyRetrieveValue(TRANSACTION_LOG_KEY) ?: ""
            val updated = if (existing.isNotEmpty()) {
                val entries = existing.split("|")
                val trimmed = if (entries.size >= MAX_LOG_ENTRIES) {
                    entries.takeLast(MAX_LOG_ENTRIES - 1)
                } else {
                    entries
                }
                (trimmed + encrypted).joinToString("|")
            } else {
                encrypted
            }
            securityManager.securelyStoreValue(TRANSACTION_LOG_KEY, updated)
        } catch (e: Exception) {
            Log.e("TransactionLogger", "Failed to persist transaction", e)
        }
    }

    private fun serializeTransaction(transaction: Transaction): String {
        return "${transaction.id};;${transaction.type};;${transaction.amount};;${transaction.currency};;${transaction.status};;${transaction.timestamp};;${transaction.description}"
    }

    fun getTransaction(id: String): Transaction? = transactionCache[id]

    fun getRecentTransactions(limit: Int = 50): List<Transaction> {
        return transactionCache.values
            .sortedByDescending { it.timestamp }
            .take(limit)
    }
}

// ==================== Wallet Manager ====================

class WalletManager(private val securityManager: SecurityManager) {

    companion object {
        private const val WALLET_BALANCE_KEY = "wallet_balance"
        private const val WALLET_CURRENCY_KEY = "wallet_currency"
        private const val WALLET_PIN_HASH_KEY = "wallet_pin_hash"
    }

    private val _balance = MutableStateFlow(WalletBalance(BigDecimal.ZERO))
    val balance: StateFlow<WalletBalance> = _balance.asStateFlow()

    private val transactionLock = Any()

    init {
        loadBalance()
    }

    private fun loadBalance() {
        try {
            val encryptedBalance = securityManager.securelyRetrieveValue(WALLET_BALANCE_KEY)
            val currency = securityManager.securelyRetrieveValue(WALLET_CURRENCY_KEY) ?: "USD"
            if (encryptedBalance != null) {
                val decrypted = securityManager.decrypt(encryptedBalance)
                val amount = BigDecimal(decrypted).setScale(2, RoundingMode.HALF_UP)
                _balance.value = WalletBalance(amount, currency)
            }
        } catch (e: Exception) {
            Log.e("WalletManager", "Failed to load balance", e)
            _balance.value = WalletBalance(BigDecimal.ZERO)
        }
    }

    private fun saveBalance(walletBalance: WalletBalance) {
        try {
            val encrypted = securityManager.encrypt(walletBalance.amount.toPlainString())
            securityManager.securelyStoreValue(WALLET_BALANCE_KEY, encrypted)
            securityManager.securelyStoreValue(WALLET_CURRENCY_KEY, walletBalance.currency)
        } catch (e: Exception) {
            Log.e("WalletManager", "Failed to save balance", e)
        }
    }

    fun topUp(amount: BigDecimal, currency: String = "USD"): WalletResult {
        return synchronized(transactionLock) {
            try {
                if (!DataSanitizer.validateAmount(amount)) {
                    return WalletResult.Error("Invalid top-up amount")
                }
                val currentBalance = _balance.value
                val newAmount = currentBalance.amount.add(amount).setScale(2, RoundingMode.HALF_UP)
                val newBalance = WalletBalance(newAmount, currency)
                _balance.value = newBalance
                saveBalance(newBalance)
                WalletResult.Success(newBalance)
            } catch (e: Exception) {
                WalletResult.Error("Top-up failed: ${e.message}")
            }
        }
    }

    fun deduct(amount: BigDecimal): WalletResult {
        return synchronized(transactionLock) {
            try {
                if (!DataSanitizer.validateAmount(amount)) {
                    return WalletResult.Error("Invalid deduction amount")
                }
                val currentBalance = _balance.value
                if (currentBalance.amount < amount) {
                    return WalletResult.Error("Insufficient balance")
                }
                val newAmount = currentBalance.amount.subtract(amount).setScale(2, RoundingMode.HALF_UP)
                val newBalance = currentBalance.copy(amount = newAmount, lastUpdated = System.currentTimeMillis())
                _balance.value = newBalance
                saveBalance(newBalance)
                WalletResult.Success(newBalance)
            } catch (e: Exception) {
                WalletResult.Error("Deduction failed: ${e.message}")
            }
        }
    }

    fun transfer(amount: BigDecimal, recipientId: String): WalletResult {
        return synchronized(transactionLock) {
            val sanitizedRecipient = DataSanitizer.sanitizeString(recipientId)
            if (sanitizedRecipient.isBlank()) {
                return WalletResult.Error("Invalid recipient")
            }
            deduct(amount)
        }
    }

    fun getBalance(): WalletBalance = _balance.value

    fun setWalletPin(pin: String) {
        val hashedPin = securityManager.hashData(pin)
        securityManager.securelyStoreValue(WALLET_PIN_HASH_KEY, hashedPin)
    }

    fun hasWalletPin(): Boolean {
        return securityManager.securelyRetrieveValue(WALLET_PIN_HASH_KEY) != null
    }
}

// ==================== Billing Manager (Google Play) ====================

class BillingManager(
    private val context: Context,
    private val securityManager: SecurityManager
) : PurchasesUpdatedListener {

    companion object {
        private const val TAG = "BillingManager"
        private const val MAX_RETRY_ATTEMPTS = 3
        private const val RETRY_DELAY_MS = 2000L
    }

    private var billingClient: BillingClient? = null
    private val _connectionState = MutableStateFlow(false)
    val connectionState: StateFlow<Boolean> = _connectionState.asStateFlow()

    private val _purchaseResult = MutableLiveData<PaymentResult>()
    val purchaseResult: LiveData<PaymentResult> = _purchaseResult

    private val _availableProducts = MutableStateFlow<List<ProductInfo>>(emptyList())
    val availableProducts: StateFlow<List<ProductInfo>> = _availableProducts.asStateFlow()

    private val pendingPurchaseCallbacks = ConcurrentHashMap<String, (PaymentResult) -> Unit>()
    private var retryCount = 0
    private val coroutineScope = CoroutineScope(Dispatchers.Main + SupervisorJob())

    fun initialize() {
        billingClient = BillingClient.newBuilder(context)
            .setListener(this)
            .enablePendingPurchases()
            .build()
        startConnection()
    }

    private fun startConnection() {
        billingClient?.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingResult) {
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    _connectionState.value = true
                    retryCount = 0
                    Log.d(TAG, "Billing client connected")
                    coroutineScope.launch {
                        processPendingPurchases()
                    }
                } else {
                    Log.e(TAG, "Billing setup failed: ${billingResult.debugMessage}")
                    _connectionState.value = false
                }
            }

            override fun onBillingServiceDisconnected() {
                _connectionState.value = false
                Log.w(TAG, "Billing service disconnected")
                retryConnection()
            }
        })
    }

    private fun retryConnection() {
        if (retryCount < MAX_RETRY_ATTEMPTS) {
            retryCount++
            coroutineScope.launch {
                delay(RETRY_DELAY_MS * retryCount)
                startConnection()
            }
        }
    }

    suspend fun queryProducts(
        productIds: List<String>,
        productType: String = BillingClient.ProductType.INAPP
    ): List<ProductInfo> {
        val client = billingClient ?: return emptyList()

        val productList = productIds.map { productId ->
            QueryProductDetailsParams.Product.newBuilder()
                .setProductId(productId)
                .setProductType(productType)
                .build()
        }

        val params = QueryProductDetailsParams.newBuilder()
            .setProductList(productList)
            .build()

        return suspendCancellableCoroutine { continuation ->
            client.queryProductDetailsAsync(params) { billingResult, productDetailsList ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    val products = productDetailsList.mapNotNull { details ->
                        val pricing = details.oneTimePurchaseOfferDetails
                        if (pricing != null) {
                            ProductInfo(
                                productId = details.productId,
                                name = details.name,
                                description = details.description,
                                price = pricing.formattedPrice,
                                priceAmountMicros = pricing.priceAmountMicros,
                                priceCurrencyCode = pricing.priceCurrencyCode,
                                productType = productType
                            )
                        } else {
                            null
                        }
                    }
                    _availableProducts.value = products
                    continuation.resumeWith(Result.success(products))
                } else {
                    Log.e(TAG, "Query products failed: ${billingResult.debugMessage}")
                    continuation.resumeWith(Result.success(emptyList()))
                }
            }
        }
    }

    suspend fun querySubscriptions(productIds: List<String>): List<ProductInfo> {
        return queryProducts(productIds, BillingClient.ProductType.SUBS)
    }

    fun launchPurchaseFlow(
        activity: Activity,
        productId: String,
        productType: String = BillingClient.ProductType.INAPP,
        callback: ((PaymentResult) -> Unit)? = null
    ) {
        val client = billingClient
        if (client == null || !_connectionState.value) {
            val error = PaymentResult.Error(-1, "Billing client not connected")
            _purchaseResult.value = error
            callback?.invoke(error)
            return
        }

        _purchaseResult.value = PaymentResult.Loading

        val productList = listOf(
            QueryProductDetailsParams.Product.newBuilder()
                .setProductId(productId)
                .setProductType(productType)
                .build()
        )

        val params = QueryProductDetailsParams.newBuilder()
            .setProductList(productList)
            .build()

        client.queryProductDetailsAsync(params) { billingResult, productDetailsList ->
            if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && productDetailsList.isNotEmpty()) {
                val productDetails = productDetailsList[0]

                val flowParams = BillingFlowParams.newBuilder()
                    .setProductDetailsParamsList(
                        listOf(
                            BillingFlowParams.ProductDetailsParams.newBuilder()
                                .setProductDetails(productDetails)
                                .build()
                        )
                    )
                    .build()

                if (callback != null) {
                    pendingPurchaseCallbacks[productId] = callback
                }

                val result = client.launchBillingFlow(activity, flowParams)
                if (result.responseCode != BillingClient.BillingResponseCode.OK) {
                    val error = PaymentResult.Error(result.responseCode, "Failed to launch billing flow: ${result.debugMessage}")
                    _purchaseResult.value = error
                    callback?.invoke(error)
                    pendingPurchaseCallbacks.remove(productId)
                }
            } else {
                val error = PaymentResult.Error(billingResult.responseCode, "Product not found: ${billingResult.debugMessage}")
                _purchaseResult.value = error
                callback?.invoke(error)
            }
        }
    }

    override fun onPurchasesUpdated(billingResult: BillingResult, purchases: MutableList<Purchase>?) {
        when (billingResult.responseCode) {
            BillingClient.BillingResponseCode.OK -> {
                purchases?.forEach { purchase ->
                    coroutineScope.launch {
                        handlePurchase(purchase)
                    }
                }
            }
            BillingClient.BillingResponseCode.USER_CANCELED -> {
                val result = PaymentResult.Cancelled()
                _purchaseResult.value = result
                notifyCallbacks(null, result)
            }
            else -> {
                val result = PaymentResult.Error(billingResult.responseCode, billingResult.debugMessage)
                _purchaseResult.value = result
                notifyCallbacks(null, result)
            }
        }
    }

    private suspend fun handlePurchase(purchase: Purchase) {
        if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
            if (!verifyPurchase(purchase)) {
                val error = PaymentResult.Error(-2, "Purchase verification failed")
                _purchaseResult.postValue(error)
                return
            }

            if (!purchase.isAcknowledged) {
                acknowledgePurchase(purchase)
            }

            val transaction = Transaction(
                id = purchase.orderId ?: UUID.randomUUID().toString(),
                type = TransactionType.IN_APP_PURCHASE,
                amount = BigDecimal.ZERO, // Actual amount from product details
                status = TransactionStatus.COMPLETED,
                description = "Purchase: ${purchase.products.joinToString()}",
                metadata = mapOf(
                    "purchaseToken" to purchase.purchaseToken,
                    "orderId" to (purchase.orderId ?: ""),
                    "products" to purchase.products.joinToString(",")
                )
            )

            val result = PaymentResult.Success(transaction)
            _purchaseResult.postValue(result)

            purchase.products.forEach { productId ->
                pendingPurchaseCallbacks[productId]?.invoke(result)
                pendingPurchaseCallbacks.remove(productId)
            }
        } else if (purchase.purchaseState == Purchase.PurchaseState.PENDING) {
            val transaction = Transaction(
                type = TransactionType.IN_APP_PURCHASE,
                amount = BigDecimal.ZERO,
                status = TransactionStatus.PENDING,
                description = "Pending purchase: ${purchase.products.joinToString()}"
            )
            _purchaseResult.postValue(PaymentResult.Success(transaction))
        }
    }

    private fun verifyPurchase(purchase: Purchase): Boolean {
        // Verify purchase signature
        // In production, verify with your backend server
        return purchase.purchaseState == Purchase.PurchaseState.PURCHASED &&
                purchase.purchaseToken.isNotEmpty()
    }

    private suspend fun acknowledgePurchase(purchase: Purchase) {
        val params = AcknowledgePurchaseParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken)
            .build()

        val client = billingClient ?: return

        suspendCancellableCoroutine<Unit> { continuation ->
            client.acknowledgePurchase(params) { billingResult ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    Log.d(TAG, "Purchase acknowledged successfully")
                } else {
                    Log.e(TAG, "Failed to acknowledge purchase: ${billingResult.debugMessage}")
                }
                continuation.resumeWith(Result.success(Unit))
            }
        }
    }

    suspend fun consumePurchase(purchaseToken: String): Boolean {
        val client = billingClient ?: return false

        val params = ConsumeParams.newBuilder()
            .setPurchaseToken(purchaseToken)
            .build()

        return suspendCancellableCoroutine { continuation ->
            client.consumeAsync(params) { billingResult, _ ->
                continuation.resumeWith(
                    Result.success(billingResult.responseCode == BillingClient.BillingResponseCode.OK)
                )
            }
        }
    }

    private suspend fun processPendingPurchases() {
        val client = billingClient ?: return

        val params = QueryPurchasesParams.newBuilder()
            .setProductType(BillingClient.ProductType.INAPP)
            .build()

        client.queryPurchasesAsync(params) { billingResult, purchasesList ->
            if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                purchasesList.forEach { purchase ->
                    if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED && !purchase.isAcknowledged) {
                        coroutineScope.launch {
                            handlePurchase(purchase)
                        }
                    }
                }
            }
        }
    }

    private fun notifyCallbacks(productId: String?, result: PaymentResult) {
        if (productId != null) {
            pendingPurchaseCallbacks[productId]?.invoke(result)
            pendingPurchaseCallbacks.remove(productId)
        } else {
            pendingPurchaseCallbacks.values.forEach { it.invoke(result) }
            pendingPurchaseCallbacks.clear()
        }
    }

    fun destroy() {
        coroutineScope.cancel()
        billingClient?.endConnection()
        billingClient = null
        pendingPurchaseCallbacks.clear()
    }
}

