class PaymentProcessor(
    private val context: Context,
    private val securityManager: SecurityManager,
    private val walletManager: WalletManager,
    private val transactionLogger: TransactionLogger,
    private val billingManager: BillingManager
) {
    companion object {
        private const val TAG = "PaymentProcessor"
    }

    private val _processingState = MutableStateFlow<PaymentResult?>(null)
    val processingState: StateFlow<PaymentResult?> = _processingState.asStateFlow()

    suspend fun processWalletTopUp(amount: BigDecimal, currency: String = "USD"): PaymentResult {
        _processingState.value = PaymentResult.Loading

        val sanitizedAmount = DataSanitizer.sanitizeAmount(amount.toPlainString())
        if (sanitizedAmount == null || !DataSanitizer.validateAmount(sanitizedAmount)) {
            val error = PaymentResult.Error(-1, "Invalid amount")
            _processingState.value = error
            return error
        }

        val transaction = Transaction(
            type = TransactionType.WALLET_TOP_UP,
            amount = sanitizedAmount,
            currency = currency,
            status = TransactionStatus.PROCESSING
        )

        transactionLogger.logTransaction(transaction)

        return try {
            // Simulate backend processing delay
            delay(500)

            val walletResult = walletManager.topUp(sanitizedAmount, currency)
            when (walletResult) {
                is WalletResult.Success -> {
                    val completedTransaction = transaction.copy(status = TransactionStatus.COMPLETED)
                    transactionLogger.logTransaction(completedTransaction)
                    val result = PaymentResult.Success(completedTransaction)
                    _processingState.value = result
                    result
                }
                is WalletResult.Error -> {
                    val failedTransaction = transaction.copy(status = TransactionStatus.FAILED)
                    transactionLogger.logTransaction(failedTransaction)
                    val result = PaymentResult.Error(-2, walletResult.message, failedTransaction)
                    _processingState.value = result
                    result
                }
                is WalletResult.Loading -> {
                    PaymentResult.Loading
                }
            }
        } catch (e: Exception) {
            val failedTransaction = transaction.copy(status = TransactionStatus.FAILED)
            transactionLogger.logTransaction(failedTransaction)
            val result = PaymentResult.Error(-3, "Processing failed: ${e.message}", failedTransaction)
            _processingState.value = result
            result
        }
    }

    suspend fun processWalletPayment(amount: BigDecimal, description: String = ""): PaymentResult {
        _processingState.value = PaymentResult.Loading

        val sanitizedAmount = DataSanitizer.sanitizeAmount(amount.toPlainString())
        val sanitizedDescription = DataSanitizer.sanitizeString(description)

        if (sanitizedAmount == null || !DataSanitizer.validateAmount(sanitizedAmount)) {
            val error = PaymentResult.Error(-1, "Invalid amount")
            _processingState.value = error
            return error
        }

        val transaction = Transaction(
            type = TransactionType.WALLET_WITHDRAWAL,
            amount = sanitizedAmount,
            status = TransactionStatus.PROCESSING,
            description = sanitizedDescription
        )

        transactionLogger.logTransaction(transaction)

        return try {
            val walletResult = walletManager.deduct(sanitizedAmount)
            when (walletResult) {
                is WalletResult.Success -> {
                    val completedTransaction = transaction.copy(status = TransactionStatus.COMPLETED)
                    transactionLogger.logTransaction(completedTransaction)
                    val result = PaymentResult.Success(completedTransaction)
                    _processingState.value = result
                    result
                }
                is WalletResult.Error -> {
                    val failedTransaction = transaction.copy(status = TransactionStatus.FAILED)
                    transactionLogger.logTransaction(failedTransaction)
                    val result = PaymentResult.Error(-2, walletResult.message, failedTransaction)
                    _processingState.value = result
                    result
                }
                is WalletResult.Loading -> PaymentResult.Loading
            }
        } catch (e: Exception) {
            val failedTransaction = transaction.copy(status = TransactionStatus.FAILED)
            transactionLogger.logTransaction(failedTransaction)
            val result = PaymentResult.Error(-3, "Payment failed: ${e.message}", failedTransaction)
            _processingState.value = result
            result
        }
    }

    suspend fun processWalletTransfer(
        amount: BigDecimal,
        recipientId: String
    ): PaymentResult {
        _processingState.value = PaymentResult.Loading

        val sanitizedAmount = DataSanitizer.sanitizeAmount(amount.toPlainString())
        val sanitizedRecipient = DataSanitizer.sanitizeString(recipientId)

        if (sanitizedAmount == null || !DataSanitizer.validateAmount(sanitizedAmount)) {
            return PaymentResult.Error(-1, "Invalid amount")
        }

        if (sanitizedRecipient.isBlank()) {
            return PaymentResult.Error(-1, "Invalid recipient")
        }

        val transaction = Transaction(
            type = TransactionType.WALLET_TRANSFER,
            amount = sanitizedAmount,
            status = TransactionStatus.PROCESSING,
            description = "Transfer to $sanitizedRecipient",
            metadata = mapOf("recipientId" to sanitizedRecipient)
        )

        transactionLogger.logTransaction(transaction)

        return try {
            val walletResult = walletManager.transfer(sanitizedAmount, sanitizedRecipient)
            when (walletResult) {
                is WalletResult.Success -> {
                    val completedTransaction = transaction.copy(status = TransactionStatus.COMPLETED)
                    transactionLogger.logTransaction(completedTransaction)
                    val result = PaymentResult.Success(completedTransaction)
                    _processingState.value = result
                    result
                }
                is WalletResult.Error -> {
                    val failedTransaction = transaction.copy(status = TransactionStatus.FAILED)
                    transactionLogger.logTransaction(failedTransaction)
                    val result = PaymentResult.Error(-2, walletResult.message, failedTransaction)
                    _processingState.value = result
                    result
                }
                is WalletResult.Loading -> PaymentResult.Loading
            }
        } catch (e: Exception) {
            val failedTransaction = transaction.copy(status = TransactionStatus.FAILED)
            transactionLogger.logTransaction(failedTransaction)
            val result = PaymentResult.Error(-3, "Transfer failed: ${e.message}", failedTransaction)
            _processingState.value = result
            result
        }
    }

    fun launchInAppPurchase(
        activity: Activity,
        productId: String,
        callback: ((PaymentResult) -> Unit)? = null
    ) {
        val sanitizedProductId = DataSanitizer.sanitizeString(productId)
        billingManager.launchPurchaseFlow(activity, sanitizedProductId, callback = callback)
    }

    fun launchSubscription(
        activity: Activity,
        productId: String,
        callback: ((PaymentResult) -> Unit)? = null
    ) {
        val sanitizedProductId = DataSanitizer.sanitizeString(productId)
        billingManager.launchPurchaseFlow(
            activity,
            sanitizedProductId,
            BillingClient.ProductType.SUBS,
            callback
        )
    }
}

// ==================== ViewModel ====================

class PaymentViewModel(
    private val paymentProcessor: PaymentProcessor,
    private val walletManager: WalletManager,
    private val billingManager: BillingManager,
    private val transactionLogger: TransactionLogger
) : ViewModel() {

    val walletBalance: StateFlow<WalletBalance> = walletManager.balance
    val availableProducts: StateFlow<List<ProductInfo>> = billingManager.availableProducts
    val billingConnected: StateFlow<Boolean> = billingManager.connectionState
    val processingState: StateFlow<PaymentResult?> = paymentProcessor.processingState

    private val _recentTransactions = MutableStateFlow<List<Transaction>>(emptyList())
    val recentTransactions: StateFlow<List<Transaction>> = _recentTransactions.asStateFlow()

    fun topUpWallet(amount: String, currency: String = "USD") {
        viewModelScope.launch {
            val sanitized = DataSanitizer.sanitizeAmount(amount)
            if (sanitized != null) {
                paymentProcessor.processWalletTopUp(sanitized, currency)
                refreshTransactions()
            }
        }
    }

    fun makeWalletPayment(amount: String, description: String = "") {
        viewModelScope.launch {
            val sanitized = DataSanitizer.sanitizeAmount(amount)
            if (sanitized != null) {
                paymentProcessor.processWalletPayment(sanitized, description)
                refreshTransactions()
            }
        }
    }

    fun transferFunds(amount: String, recipientId: String) {
        viewModelScope.launch {
            val sanitized = DataSanitizer.sanitizeAmount(amount)
            if (sanitized != null) {
                paymentProcessor.processWalletTransfer(sanitized, recipientId)
                refreshTransactions()
            }
        }
    }

    fun purchaseProduct(activity: Activity, productId: String) {
        paymentProcessor.launchInAppPurchase(activity, productId) { result ->
            viewModelScope.launch {
                refreshTransactions()
            }
        }
    }

    fun purchaseSubscription(activity: Activity, productId: String) {
        paymentProcessor.launchSubscription(activity, productId) { result ->
            viewModelScope.launch {
                refreshTransactions()
            }
        }
    }

    fun loadProducts(productIds: List<String>) {
        viewModelScope.launch {
            billingManager.queryProducts(productIds)
        }
    }

    fun loadSubscriptions(productIds: List<String>) {
        viewModelScope.launch {
            billingManager.querySubscriptions(productIds)
        }
    }

    fun refreshTransactions() {
        _recentTransactions.value = transactionLogger.getRecentTransactions()
    }

    override fun onCleared() {
        super.onCleared()
        billingManager.destroy()
    }
}

// ==================== Module Initializer / DI ====================

class PaymentModule private constructor(
    val securityManager: SecurityManager,
    val walletManager: WalletManager,
    val transactionLogger: TransactionLogger,
    val billingManager: BillingManager,
    val paymentProcessor: PaymentProcessor
) {
    companion object {
        @Volatile
        private var instance: PaymentModule? = null

        fun initialize(context: Context): PaymentModule {
            return instance ?: synchronized(this) {
                instance ?: buildModule(context.applicationContext).also { instance = it }
            }
        }

        fun getInstance(): PaymentModule {
            return instance ?: throw IllegalStateException(
                "PaymentModule not initialized. Call PaymentModule.initialize(context) first."
            )
        }

        private fun buildModule(context: Context): PaymentModule {
            val securityManager = SecurityManager(context)
            val walletManager = WalletManager(securityManager)
            val transactionLogger = TransactionLogger(securityManager)
            val billingManager = BillingManager(context, securityManager)
            val paymentProcessor = PaymentProcessor(
                context,
                securityManager,
                walletManager,
                transactionLogger,
                billingManager
            )

            billingManager.initialize()

            return PaymentModule(
                securityManager,
                walletManager,
                transactionLogger,
                billingManager,
                paymentProcessor
            )
        }
    }

    fun createViewModel(): PaymentViewModel {
        return PaymentViewModel(
            paymentProcessor,
            walletManager,
            billingManager,
            transactionLogger
        )
    }

    fun destroy() {
        billingManager.destroy()
        instance = null
    }
}

// ==================== Rate Limiter for API Security ====================

class RateLimiter(
    private val maxRequests: Int = 10,
    private val windowMillis: Long = 60_000L
) {
    private val requestTimestamps = mutableListOf<Long>()
    private val lock = Any()

    fun allowRequest(): Boolean {
        synchronized(lock) {
            val now = System.currentTimeMillis()
            requestTimestamps.removeAll { now - it > windowMillis }
            return if (requestTimestamps.size < maxRequests) {
                requestTimestamps.add(now)
                true
            } else {
                false
            }
        }
    }

    fun reset() {
        synchronized(lock) {
            requestTimestamps.clear()
        }
    }
}

// ==================== Device Compatibility Helper ====================

object DeviceCompatibility {

    fun getSecurityLevel(): SecurityLevel {
        return when {
            Build.VERSION.SDK_INT >= Build.VERSION_CODES.P &&
                    hasStrongBox() -> SecurityLevel.HARDWARE_STRONGBOX
            Build.VERSION.SDK_INT >= Build.VERSION_CODES.M -> SecurityLevel.HARDWARE_KEYSTORE
            Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP -> SecurityLevel.SOFTWARE_KEYSTORE
            else -> SecurityLevel.BASIC
        }
    }

    private fun hasStrongBox(): Boolean {
        return try {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
                val keyStore = KeyStore.getInstance("AndroidKeyStore")
                keyStore.load(null)
                true // StrongBox availability checked during key generation
            } else {
                false
            }
        } catch (e: Exception) {
            false
        }
    }

    fun isDeviceSecure(context: Context): Boolean {
        val keyguardManager = context.getSystemService(Context.KEYGUARD_SERVICE) as? android.app.KeyguardManager
        return keyguardManager?.isDeviceSecure ?: false
    }

    fun supportsBiometric(context: Context): Boolean {
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
            val biometricManager = context.getSystemService(Context.FINGERPRINT_SERVICE)
            biometricManager != null
        } else {
            false
        }
    }

    enum class SecurityLevel {
        BASIC,
        SOFTWARE_KEYSTORE,
        HARDWARE_KEYSTORE,
        HARDWARE_STRONGBOX
    }
}